function send_sales_invoice_pdf_on_whatsapp(frm) {
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'Customer',
            filters: { name: frm.doc.customer },
            fieldname: 'custom_whatsapp_phone_nubmer'
        },
        callback: function (response) {
            let number = response.message ? response.message.custom_whatsapp_phone_nubmer : null;

            if (!number) {
                frappe.msgprint(__('Customer WhatsApp number is not available. رقم واتساب العميل غير متوفر.'));
                return;
            }

            let digits = number.replace(/[^0-9]/g, '');

            // Normalize Saudi format (e.g. 0501234567 => 966501234567)
            if (digits.startsWith('0') && digits.length === 10) {
                digits = '966' + digits.slice(1);
            } else if (digits.startsWith('966') && digits.length === 12) {
                // already in correct format
            } else {
                frappe.msgprint(__('Invalid or unsupported number format. يرجى إدخال الرقم بصيغة سعودية مثل 05XXXXXXXX أو +966XXXXXXXXX'));
                return;
            }

            const base_url = window.location.origin;
            const pdf_url = `${base_url}/api/method/frappe.utils.print_format.download_pdf` +
                `?doctype=Sales%20Invoice&name=${encodeURIComponent(frm.doc.name)}` +
                `&format=%D8%B7%D8%A8%D8%A7%D8%B9%D9%87%20pos%20%D9%85%D8%A8%D9%8A%D8%B9%D8%A7%D8%AA&no_letterhead=0&letterhead=Letter%20Heads&_lang=ar`;

            const message =
                `🧾 *فاتورة مبيعات*\n\n` +
                `📌 رقم الفاتورة: *${frm.doc.name}*\n` +
                `📅 التاريخ: *${frm.doc.posting_date}*\n\n` +
                `📥 لتحميل نسخة PDF من الفاتورة، اضغط على الرابط التالي:\n${pdf_url}`;

            const whatsapp_url = `https://wa.me/${digits}?text=${encodeURIComponent(message)}`;

            window.open(whatsapp_url, '_blank');
        },
        error: function (error) {
            console.error('Error fetching WhatsApp number:', error);
            frappe.msgprint(__('An error occurred while fetching the WhatsApp number. حدث خطأ أثناء جلب رقم الواتساب.'));
        }
    });
}

