function send_quotation_pdf_on_whatsapp(frm) {
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'Customer',
            filters: { name: frm.doc.party_name },
            fieldname: 'custom_whatsapp_phone_nubmer'
        },
        callback: function (response) {
            let number = response.message && response.message.custom_whatsapp_phone_nubmer
                ? response.message.custom_whatsapp_phone_nubmer
                : frm.doc.custom_whatsapp_phone_nubmer;

            if (!number) {
                frappe.msgprint(__('WhatsApp number not available on Customer or Quotation. رقم الواتساب غير متوفر.'));
                return;
            }

            let digits = number.replace(/\D/g, '');
            if (digits.startsWith('0')) {
                digits = '+966' + digits.slice(1);
            } else if (digits.startsWith('966')) {
                digits = '+' + digits;
            } else if (!digits.startsWith('+')) {
                digits = '+966' + digits;
            }

            if (digits.length < 12) {
                frappe.msgprint(__('Invalid WhatsApp number. رقم الواتساب غير صالح.'));
                return;
            }

            const format = "عرض الأسعار واتس"; // Change if needed
            const letterhead = "واتس";

            const base_url = window.location.origin;
            const pdf_url = `${base_url}/api/method/frappe.utils.print_format.download_pdf` +
                `?doctype=Quotation&name=${encodeURIComponent(frm.doc.name)}` +
                `&format=${encodeURIComponent(format)}&no_letterhead=0&letterhead=${encodeURIComponent(letterhead)}&_lang=ar`;

            const message = `🧾 *Quotation PDF | رابط العرض:*\n${pdf_url}`;
            const whatsapp_url = `https://web.whatsapp.com/send?phone=${digits}&text=${encodeURIComponent(message)}`;

            window.open(whatsapp_url, '_blank');
        },
        error: function (error) {
            console.error('Error fetching WhatsApp number:', error);
            frappe.msgprint(__('An error occurred while fetching the WhatsApp number. حدث خطأ أثناء جلب رقم الواتساب.'));
        }
    });
}

