function send_sales_invoice_pdf_on_whatsapp(frm) {
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'Customer',
            filters: { name: frm.doc.customer },
            fieldname: 'mobile_no'
        },
        callback: function (response) {
            let number = response.message ? response.message.mobile_no : null;

            if (!number) {
                frappe.msgprint(__('Customer WhatsApp number is not available. رقم واتساب العميل غير متوفر.'));
                return;
            }

            let digits = number.replace(/\D/g, '');

            // Convert to international format if local (Saudi)
            if (digits.startsWith('0')) {
                digits = '+966' + digits.slice(1);
            } else if (digits.startsWith('966')) {
                digits = '+' + digits;
            } else if (!digits.startsWith('+')) {
                digits = '+966' + digits;
            }

            if (digits.length < 12) {
                frappe.msgprint(__('Invalid WhatsApp number. رقم الواتساب غير صالح.'));
                return;
            }

            const base_url = window.location.origin;
            const pdf_url = `${base_url}/api/method/frappe.utils.print_format.download_pdf` +
                `?doctype=Sales%20Invoice&name=${encodeURIComponent(frm.doc.name)}` +
                `&format=طباعه%20pos%20مبيعات&no_letterhead=0&letterhead=Letter%20Heads&_lang=ar`;

            const message = `🧾 *Sales Invoice PDF | رابط الفاتورة:*\n${pdf_url}`;
            const whatsapp_url = `https://web.whatsapp.com/send?phone=${digits}&text=${encodeURIComponent(message)}`;

            window.open(whatsapp_url, '_blank');
        },
        error: function (error) {
            console.error('Error fetching WhatsApp number:', error);
            frappe.msgprint(__('An error occurred while fetching the WhatsApp number. حدث خطأ أثناء جلب رقم الواتساب.'));
        }
    });
}

